features.snippet:
interface Bus;
  logic [7:0] data;
  logic valid;
endinterface

module consumer(Bus b);
  logic [7:0] r;
  always_comb r = b.data;
endmodule

module top;
  Bus b();
  consumer c(.b(b));
endmodule

interface Ctrl;
  logic req;
  logic ack;
endinterface

module driver(Ctrl.master c);
  assign c.req = 1'b1;
endmodule

module receiver(Ctrl c);
  logic r;
  always_comb r = c.req;
endmodule

module top;
  Ctrl c();
  driver  d(.c(c));
  receiver rx(.c(c));
endmodule

interface MyIf;
  input logic sel;
  logic [3:0] addr;
endinterface

module sub(MyIf ifc);
  logic out;
  assign out = ifc.sel & ifc.addr[0];
endmodule

module top;
  MyIf ifc();
  sub s(.ifc(ifc));
endmodule
